:root {
  /* Color system */
  --color-primary-lime: #E8FF87;
  --color-primary-soft-blue: #B7DDE8;
  --color-secondary-teal: #004C3F;
  --color-secondary-blue: #0084D6;
  --color-accent-blue: #0060C8;

  --color-neutral-0: #FFFFFF;
  --color-neutral-100: #F3F4F5;
  --color-neutral-900: #222A2A;

  --color-success: #21A179;
  --color-error: #E95757;
  --color-warning: #F5B02E;
  --color-info: #1E88E5;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'IBM Plex Sans', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --fs-h1: 40px;
  --fs-h2: 32px;
  --fs-h3: 24px;
  --fs-body: 16px;
  --fs-small: 14px;

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.75;

  /* Spacing (8px base scale) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Radii & shadows */
  --radius-sm: 8px;
  --radius-md: 16px;
  --radius-lg: 24px;
  --radius-pill: 32px;

  --shadow-soft: 0 18px 45px rgba(0, 0, 0, 0.08);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--color-primary-soft-blue);
  color: var(--color-neutral-900);
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-normal);
  -webkit-font-smoothing: antialiased;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-accent-blue);
  outline-offset: 2px;
}

img {
  max-width: 100%;
  display: block;
}

/* Layout shell aligns with header/footer containers in the design */

.shell {
  width: min(1120px, 100% - 48px);
  margin-inline: auto;
}

.site-header {
  padding: var(--space-4) 0 var(--space-3);
}

.site-header-inner {
  background-color: var(--color-primary-lime);
  border-radius: var(--radius-pill);
  padding: 20px 32px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-3);
  box-shadow: var(--shadow-soft);
}

/* Brand / Logo */

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  color: var(--color-neutral-0);
  text-decoration: none;
}

.brand-mark {
  width: 32px;
  height: 32px;
  border-radius: 12px;
  border: 2px solid rgba(255, 255, 255, 0.9);
  position: relative;
}

.brand-mark::before,
.brand-mark::after {
  content: '';
  position: absolute;
  border-radius: 6px;
}

/* Inner chip square */
.brand-mark::before {
  inset: 5px;
  border: 1px solid rgba(255, 255, 255, 0.75);
}

/* Simple "pins" hinting at a processor */
.brand-mark::after {
  inset: 2px;
  border: 1px dashed rgba(255, 255, 255, 0.55);
}

.brand-text {
  font-family: var(--font-heading);
  font-weight: var(--fw-semibold);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  font-size: 13px;
}

/* Primary navigation */

.primary-nav {
  flex: 1;
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 32px;
}

.nav-item {
  flex-shrink: 0;
}

.nav-link {
  font-family: var(--font-heading);
  font-size: 15px;
  font-weight: var(--fw-medium);
  color: var(--color-secondary-teal);
  padding-block: 4px;
  position: relative;
  letter-spacing: 0.01em;
}

.nav-link::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: -4px;
  height: 2px;
  border-radius: 999px;
  background-color: transparent;
  transition: background-color 160ms ease-out, transform 160ms ease-out;
  transform-origin: center;
  transform: scaleX(0.6);
}

.nav-link:hover,
.nav-link:focus-visible {
  color: var(--color-accent-blue);
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
  background-color: var(--color-accent-blue);
  transform: scaleX(1);
}

.nav-link.is-current {
  color: var(--color-accent-blue);
}

.nav-link.is-current::after {
  background-color: var(--color-accent-blue);
  transform: scaleX(1);
}

/* Main content wrapper */

.site-main {
  padding: var(--space-4) 0 var(--space-6);
}

.site-main > .shell {
  background: transparent;
}

/* Footer styling - soft card with rounded top corners */

.site-footer {
  padding: 0 0 var(--space-4);
}

.site-footer-panel {
  background-color: var(--color-neutral-0);
  border-radius: var(--radius-lg) var(--radius-lg) 0 0;
  padding: 32px 32px 24px;
  box-shadow: 0 -12px 40px rgba(0, 0, 0, 0.06);
}

.footer-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-4);
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
  padding-bottom: var(--space-3);
}

.footer-brand-block {
  max-width: 320px;
}

.brand--footer {
  color: var(--color-secondary-teal);
  margin-bottom: var(--space-1);
}

.footer-tagline {
  margin: 0;
  font-size: var(--fs-small);
  line-height: var(--lh-relaxed);
  color: rgba(34, 42, 42, 0.8);
}

.footer-nav {
  flex: 1;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 12px 32px;
  justify-content: flex-end;
}

.footer-link-item {
  min-width: 160px;
}

.footer-link {
  font-size: var(--fs-small);
  font-weight: var(--fw-medium);
  color: var(--color-secondary-teal);
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-accent-blue);
}

.footer-bottom {
  padding-top: var(--space-2);
}

.footer-meta {
  margin: 0;
  font-size: 12px;
  color: rgba(34, 42, 42, 0.6);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .site-header-inner {
    flex-direction: column;
    align-items: flex-start;
    padding-inline: 24px;
  }

  .nav-list {
    flex-wrap: wrap;
    justify-content: flex-start;
    gap: 16px 24px;
  }

  .site-main {
    padding-top: var(--space-3);
  }

  .footer-top {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-links {
    justify-content: flex-start;
  }
}

@media (max-width: 640px) {
  .shell {
    width: min(100% - 32px, 1120px);
  }

  .site-header-inner {
    padding: 16px 20px;
  }

  .nav-list {
    flex-direction: column;
    align-items: flex-start;
  }

  .site-footer-panel {
    padding: 24px 20px 20px;
  }

  .footer-links {
    gap: 8px 16px;
  }
}
